{
  "success": true,
  "data": {
    "query": "regulation service eligibility requirements resource participation ancillary service must offer mileage",
    "num_results": 10,
    "filters_applied": {
      "market": "CAISO",
      "data_type": null,
      "year_start": null,
      "year_end": null,
      "range_type": null
    },
